import{c as i,Q as e,j as a,m as o}from"./chunks/framework.j5cTrcw1.js";const u=JSON.parse('{"title":"节点批量化部署设计与进度","description":"","frontmatter":{},"headers":[],"relativePath":"node-batch-deploy.md","filePath":"node-batch-deploy.md"}'),s={name:"node-batch-deploy.md"};function t(n,l,d,p,c,r){return e(),a("div",null,[...l[0]||(l[0]=[o(`<h1 id="节点批量化部署设计与进度" tabindex="-1">节点批量化部署设计与进度 <a class="header-anchor" href="#节点批量化部署设计与进度" aria-label="Permalink to &quot;节点批量化部署设计与进度&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>这份文档用于回顾你提出的需求，并整理当前已经在 flvxt2 中完成的改造内容。</p><p>这次目标不是把整个 S-UI 面板塞进 flvxt2，也不是复制一套完整 S-UI 管理系统。真正目标是：把 S-uiR 中对本项目有价值的部分能力抽出来，整合进 flvxt2 的节点管理，让 flvxt2 能通过模板生成节点入站配置，并在每台服务器的关键字段上做随机化，最后把完整 core 配置文件下发到节点运行。</p><p>整体部署路径是“面板轻控制，节点跑配置”：</p><ol><li>面板负责编辑 TLS 模板、节点身份、入站模板和已部署入站。</li><li>后端负责渲染完整 core 配置。</li><li>配置通过现有节点 WebSocket 通道下发。</li><li>节点写入配置文件，并用本地 core 运行。</li><li>面板提供可复制的节点连接信息，方便直接使用。</li></ol><h2 id="你的需求回顾" tabindex="-1">你的需求回顾 <a class="header-anchor" href="#你的需求回顾" aria-label="Permalink to &quot;你的需求回顾&quot;">​</a></h2><p>你一路提出的核心需求可以整理为：</p><ul><li>在 flvxt2 现有节点功能中增加“批量化部署”能力。</li><li>通过模板部署节点。</li><li>在关键字段上随机化，避免不同机器出现完全相同的配置。</li><li>只整合 S-uiR 的部分能力，不整合整个 S-UI 面板。</li><li>需要 TLS 管理，尤其是 Reality 等 TLS/伪装相关设置。</li><li>需要入站管理，类似 S-UI 的入站编辑能力。</li><li>需要类似 S-uiR 用户管理的能力，但这里每个服务器/节点都可以理解成一个用户。</li><li>在节点页面增加节点部署按钮。</li><li>部署按钮唤起二级部署菜单或弹窗。</li><li>部署时使用服务器绑定的 UUID 和其它随机凭据。</li><li>部署时可以选择协议、TLS 模板、端口、地址和入站参数。</li><li>默认监听地址使用回环地址。</li><li>节点部署名称如果不设置，默认为“节点名字 + 协议名字”。</li><li>如果部署名称重复，则自动追加数字。</li><li>节点页面需要能查看已经部署的节点入站。</li><li>下发方式不是通过 UI 直接控制运行逻辑，而是编辑节点上的配置文件。</li><li>节点以内核方式运行生成的配置，也就是直接跳过 UI。</li><li>面板只负责编辑节点、生成配置、下发配置。</li><li>已部署节点信息必须可以复制，从而直接使用。</li><li>二维码必须完全离线生成，不能调用外部 QR API。</li><li>新功能整体需要尽量离线可用。</li></ul><h2 id="从-s-uir-借鉴的思路" tabindex="-1">从 S-uiR 借鉴的思路 <a class="header-anchor" href="#从-s-uir-借鉴的思路" aria-label="Permalink to &quot;从 S-uiR 借鉴的思路&quot;">​</a></h2><p>当前实现不是照搬 S-uiR，而是借鉴了这些概念：</p><ul><li>TLS 模板： <ul><li>可复用的服务端 TLS JSON。</li><li>可复用的客户端 TLS JSON。</li></ul></li><li>Reality 支持： <ul><li>服务端 Reality 字段。</li><li>客户端 Reality 字段。</li><li>short ID 处理。</li></ul></li><li>用户/客户端概念： <ul><li>在 flvxt2 中，每个节点拥有自己的固定身份。</li><li>这个身份类似 S-uiR 里的用户或客户端。</li></ul></li><li>入站动态参数： <ul><li>协议相关入站参数用 JSON 保存。</li><li>渲染配置时合并到最终入站配置中。</li></ul></li></ul><h2 id="当前架构" tabindex="-1">当前架构 <a class="header-anchor" href="#当前架构" aria-label="Permalink to &quot;当前架构&quot;">​</a></h2><h3 id="数据模型" tabindex="-1">数据模型 <a class="header-anchor" href="#数据模型" aria-label="Permalink to &quot;数据模型&quot;">​</a></h3><p>新增了几类持久化模型：</p><ul><li><code>NodeTLSTemplate</code><ul><li>保存 TLS 或 Reality 模板。</li><li>包含服务端 JSON 和客户端 JSON。</li></ul></li><li><code>NodeIdentity</code><ul><li>保存每个节点绑定的随机身份和凭据。</li><li>包含 UUID、各协议密码、Reality short ID、路径后缀、服务后缀等。</li></ul></li><li><code>NodeDeployedInbound</code><ul><li>保存某个节点已经部署的入站定义。</li><li>保存渲染后的服务端配置、客户端配置、分享链接、监听地址、发布地址、端口等。</li></ul></li><li><code>NodeConfigRevision</code><ul><li>保存生成过的 core 配置版本。</li><li>包含 checksum 和部署状态。</li></ul></li><li><code>NodeDeployLog</code><ul><li>保存部署、回滚、删除、应用配置等操作日志。</li></ul></li></ul><p>这些模型已经加入仓库的自动迁移。</p><h3 id="后端-api" tabindex="-1">后端 API <a class="header-anchor" href="#后端-api" aria-label="Permalink to &quot;后端 API&quot;">​</a></h3><p>新增了这些节点部署接口：</p><ul><li><code>/api/v1/node/tls-template/list</code></li><li><code>/api/v1/node/tls-template/save</code></li><li><code>/api/v1/node/tls-template/delete</code></li><li><code>/api/v1/node/deploy/detail</code></li><li><code>/api/v1/node/deploy/identity/regenerate</code></li><li><code>/api/v1/node/deploy/inbound/save</code></li><li><code>/api/v1/node/deploy/inbound/delete</code></li><li><code>/api/v1/node/deploy/apply</code></li><li><code>/api/v1/node/deploy/rollback</code></li></ul><p>后端当前渲染的是 sing-box 风格配置：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;log&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;level&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;warning&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;inbounds&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;outbounds&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;direct&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;tag&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;direct&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>启用状态的已部署入站会被渲染进 <code>inbounds</code>。</p><p>每个入站会保存：</p><ul><li>服务端配置 JSON。</li><li>客户端配置 JSON。</li><li>分享 URI。</li><li>入站参数 JSON。</li><li>选中的 TLS 模板。</li></ul><h3 id="节点身份" tabindex="-1">节点身份 <a class="header-anchor" href="#节点身份" aria-label="Permalink to &quot;节点身份&quot;">​</a></h3><p>每个节点都会获得一个稳定的随机身份。除非手动重新生成，否则这个身份会保持不变。</p><p>当前生成的字段包括：</p><ul><li>VLESS UUID。</li><li>mixed/SOCKS/HTTP 使用的密码。</li><li>Trojan 密码。</li><li>Hysteria2 密码。</li><li>TUIC UUID 和密码。</li><li>Reality short ID。</li><li>路径后缀。</li><li>服务后缀。</li><li>seed。</li></ul><p>这满足了“把每一个节点都当成一个用户/客户端”的需求。</p><h3 id="名称生成" tabindex="-1">名称生成 <a class="header-anchor" href="#名称生成" aria-label="Permalink to &quot;名称生成&quot;">​</a></h3><p>如果部署表单没有指定名称，后端会按你的要求生成默认名称：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点名字 + 协议名字</span></span></code></pre></div><p>当前代码中的格式是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;节点名&gt;-&lt;协议名大写&gt;</span></span></code></pre></div><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hk-node-VLESS</span></span></code></pre></div><p>如果同一个节点下已经存在相同部署名称，后端会自动追加数字后缀。</p><h3 id="tls-和-reality-模板" tabindex="-1">TLS 和 Reality 模板 <a class="header-anchor" href="#tls-和-reality-模板" aria-label="Permalink to &quot;TLS 和 Reality 模板&quot;">​</a></h3><p>TLS 模板分成两段 JSON：</p><ul><li><code>serverJson</code><ul><li>合并到服务端入站配置的 <code>tls</code> 字段。</li></ul></li><li><code>clientJson</code><ul><li>写入生成出来的客户端配置。</li></ul></li></ul><p>Reality 模板有额外处理：</p><ul><li>强制开启 <code>reality.enabled</code>。</li><li>如果服务端模板没有指定 short ID，则自动注入节点绑定的 Reality short ID。</li><li>如果客户端模板没有指定 short ID，也自动注入节点绑定的 Reality short ID。</li></ul><p>前端 TLS 表单支持通过常见字段生成 JSON：</p><ul><li>SNI / server name。</li><li>fingerprint。</li><li>证书文件路径。</li><li>私钥文件路径。</li><li>证书内容。</li><li>私钥内容。</li><li>insecure 开关。</li><li>Reality 握手服务器。</li><li>Reality 握手端口。</li><li>Reality private key。</li><li>Reality public key。</li><li>Reality short IDs。</li></ul><h3 id="入站管理" tabindex="-1">入站管理 <a class="header-anchor" href="#入站管理" aria-label="Permalink to &quot;入站管理&quot;">​</a></h3><p>部署弹窗当前支持这些协议：</p><ul><li>VLESS。</li><li>Hysteria2。</li><li>Trojan。</li><li>Shadowsocks。</li><li>TUIC。</li><li>SOCKS。</li><li>HTTP。</li></ul><p>当前已暴露的协议字段包括：</p><ul><li>VLESS： <ul><li>flow。</li><li>transport type。</li><li>transport path。</li></ul></li><li>Hysteria2： <ul><li>up Mbps。</li><li>down Mbps。</li><li>obfs password。</li></ul></li><li>Shadowsocks： <ul><li>method。</li></ul></li><li>TUIC： <ul><li>congestion control。</li></ul></li><li>Trojan / SOCKS / HTTP： <ul><li>默认使用节点绑定凭据。</li></ul></li></ul><p>此外还保留了高级 JSON 编辑器，用于填写更细的协议参数。</p><h3 id="配置下发与-core-运行" tabindex="-1">配置下发与 core 运行 <a class="header-anchor" href="#配置下发与-core-运行" aria-label="Permalink to &quot;配置下发与 core 运行&quot;">​</a></h3><p>节点侧 WebSocket reporter 现在支持这些命令：</p><ul><li><code>ApplyCoreConfig</code></li><li><code>GetCoreConfig</code></li><li><code>RestartCore</code></li></ul><p>执行 <code>ApplyCoreConfig</code> 时，节点会：</p><ol><li>接收 <code>coreType</code>、<code>configJson</code> 和 <code>checksum</code>。</li><li>如果提供了 checksum，则校验配置内容。</li><li>校验配置必须是合法 JSON。</li><li>写入临时配置文件。</li><li>如果是 sing-box 配置，则执行 <code>sing-box check -c</code>。</li><li>备份旧配置。</li><li>替换目标配置文件。</li><li>创建或更新本地 systemd 服务。</li><li>重启 core 服务。</li><li>如果重启失败，回滚配置文件。</li></ol><p>Linux 下 sing-box 配置路径是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/etc/flvxt2/sing-box.json</span></span></code></pre></div><p>托管的 systemd 服务名是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>flvxt2-sing-box</span></span></code></pre></div><p>服务运行命令是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sing-box run -c /etc/flvxt2/sing-box.json</span></span></code></pre></div><p>离线规则：</p><ul><li>节点不会自动下载 <code>sing-box</code>。</li><li>如果节点本机没有安装 <code>sing-box</code>，部署会明确失败并提示。</li></ul><h3 id="前端页面" tabindex="-1">前端页面 <a class="header-anchor" href="#前端页面" aria-label="Permalink to &quot;前端页面&quot;">​</a></h3><p>节点页面现在增加了部署入口：</p><ul><li>节点卡片/网格视图中有部署入口。</li><li>节点列表视图中也有部署入口。</li></ul><p>部署弹窗包含：</p><ul><li>节点身份查看。</li><li>节点身份重新生成。</li><li>入站创建和编辑。</li><li>TLS/Reality 模板创建。</li><li>已部署入站列表。</li><li>配置预览。</li><li>配置版本列表。</li><li>配置回滚。</li><li>部署日志。</li><li>多种复制按钮。</li><li>离线二维码预览。</li></ul><h3 id="可复制的节点信息" tabindex="-1">可复制的节点信息 <a class="header-anchor" href="#可复制的节点信息" aria-label="Permalink to &quot;可复制的节点信息&quot;">​</a></h3><p>每个已部署入站支持复制：</p><ul><li>分享 URI。</li><li>客户端 JSON。</li><li>sing-box outbound JSON。</li><li>Mihomo/Clash proxy 片段。</li><li>QR payload。</li></ul><p>二维码预览使用本地 SVG 渲染，不调用任何外部二维码服务。</p><h2 id="完全离线状态" tabindex="-1">完全离线状态 <a class="header-anchor" href="#完全离线状态" aria-label="Permalink to &quot;完全离线状态&quot;">​</a></h2><p>新节点部署功能本身按完全离线目标设计：</p><ul><li>不调用外部二维码 API。</li><li>部署弹窗不依赖 CDN。</li><li>节点应用配置时不远程下载 core。</li><li>节点使用本机已经安装的 core 可执行文件。</li><li>面板通过现有 WebSocket 通道下发渲染好的配置。</li></ul><p>需要注意一个边界：</p><ul><li>flvxt2 项目中其它旧功能仍然包含在线能力，例如升级检查、安装链接、IP 探测、支付接口、文档链接等。</li><li>本次新增的节点部署功能自身已经按离线方式处理。</li></ul><h2 id="已新增或修改的文件" tabindex="-1">已新增或修改的文件 <a class="header-anchor" href="#已新增或修改的文件" aria-label="Permalink to &quot;已新增或修改的文件&quot;">​</a></h2><h3 id="后端" tabindex="-1">后端 <a class="header-anchor" href="#后端" aria-label="Permalink to &quot;后端&quot;">​</a></h3><ul><li><code>go-backend/internal/store/model/model.go</code><ul><li>新增部署相关模型。</li></ul></li><li><code>go-backend/internal/store/repo/repository.go</code><ul><li>注册自动迁移。</li></ul></li><li><code>go-backend/internal/store/repo/repository_node_deploy.go</code><ul><li>新增部署相关仓库操作。</li></ul></li><li><code>go-backend/internal/http/handler/handler.go</code><ul><li>注册部署路由。</li></ul></li><li><code>go-backend/internal/http/handler/node_deploy.go</code><ul><li>新增 TLS 模板、节点身份、入站、下发、回滚等 handler。</li></ul></li></ul><h3 id="节点-agent" tabindex="-1">节点 Agent <a class="header-anchor" href="#节点-agent" aria-label="Permalink to &quot;节点 Agent&quot;">​</a></h3><ul><li><code>go-gost/x/socket/websocket_reporter.go</code><ul><li>新增 core 配置下发、读取、重启命令。</li><li>新增离线 sing-box 校验。</li><li>新增 systemd 服务创建和管理。</li></ul></li></ul><h3 id="前端" tabindex="-1">前端 <a class="header-anchor" href="#前端" aria-label="Permalink to &quot;前端&quot;">​</a></h3><ul><li><code>vite-frontend/src/api/types.ts</code><ul><li>新增部署相关 API 类型。</li></ul></li><li><code>vite-frontend/src/api/index.ts</code><ul><li>新增部署相关 API 方法。</li></ul></li><li><code>vite-frontend/src/pages/node.tsx</code><ul><li>新增部署弹窗状态和部署入口。</li></ul></li><li><code>vite-frontend/src/pages/node/node-list-view.tsx</code><ul><li>新增列表视图部署按钮。</li></ul></li><li><code>vite-frontend/src/pages/node/node-deploy-modal.tsx</code><ul><li>新增部署弹窗。</li><li>新增离线二维码渲染器。</li></ul></li></ul><h2 id="已完成验证" tabindex="-1">已完成验证 <a class="header-anchor" href="#已完成验证" aria-label="Permalink to &quot;已完成验证&quot;">​</a></h2><p>已经完成的检查：</p><ul><li><code>go build ./cmd/paneld</code></li><li><code>go test -count=1 ./socket</code></li><li><code>go test ./internal/store/repo</code></li><li><code>git diff --check</code></li><li>确认部署弹窗没有引用外部二维码服务。</li></ul><p>已知验证限制：</p><ul><li>当前环境无法完成前端 build： <ul><li><code>node.exe</code> 执行时报 <code>Access is denied</code>。</li><li><code>vite-frontend/node_modules</code> 不存在。</li></ul></li><li><code>go test ./internal/http/handler</code> 当前失败： <ul><li>失败原因是现有测试仍在用旧的 <code>New(repo, secret)</code> 两参数构造函数。</li><li>当前代码库中的 handler 构造函数需要三个参数。</li><li>这个问题看起来不是本次节点部署功能引入的。</li></ul></li></ul><h2 id="剩余工作" tabindex="-1">剩余工作 <a class="header-anchor" href="#剩余工作" aria-label="Permalink to &quot;剩余工作&quot;">​</a></h2><p>建议下一步继续做：</p><ul><li>在具备前端依赖的环境中运行 TypeScript 和 Vite build。</li><li>用浏览器实际测试部署弹窗交互。</li><li>找一台已经本地安装 <code>sing-box</code> 的节点做真实下发测试。</li><li>补后端测试： <ul><li>入站参数 JSON 解析。</li><li>默认名称生成。</li><li>重名数字后缀。</li><li>Reality short ID 注入。</li><li>配置渲染。</li></ul></li><li>补节点 Agent 测试： <ul><li>checksum 不匹配。</li><li>非法 JSON。</li><li>本机缺少 <code>sing-box</code>。</li><li>systemd unit 生成。</li></ul></li><li>可以增加服务端 Reality keypair 生成功能。</li><li>决定 TLS 模板是否需要独立的全局管理页面，而不是只放在节点部署弹窗中。</li><li>根据客户端兼容性，继续完善各协议分享 URI 的参数生成。</li></ul><h2 id="当前实现状态" tabindex="-1">当前实现状态 <a class="header-anchor" href="#当前实现状态" aria-label="Permalink to &quot;当前实现状态&quot;">​</a></h2><p>当前实现已经不是 Demo，而是节点部署功能的第一个真实版本：</p><ul><li>面板可以定义 TLS/Reality 模板。</li><li>面板可以为每个节点绑定随机身份和凭据。</li><li>面板可以为节点创建已部署入站。</li><li>后端可以渲染完整 sing-box 配置版本。</li><li>面板可以把配置下发到节点。</li><li>节点可以应用配置，并通过本地 sing-box systemd 服务运行。</li><li>面板可以展示并复制已部署节点信息。</li></ul><p>当前主要风险是前端 build 和浏览器运行时还没有在本环境完成验证，因为当前本地环境缺少前端依赖。</p>`,97)])])}const k=i(s,[["render",t]]);export{u as __pageData,k as default};
